public interface IFileUploadService
{
    Task<FileUploadResult> UploadFileAsync(IFormFile file, string category);
    bool IsAllowedFileType(string fileName);
    bool IsAllowedFileSize(long fileSize);
}

public class FileUploadService : IFileUploadService
{
    private readonly IWebHostEnvironment _environment;
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    private static readonly HashSet<string> AllowedExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        // Images
        ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", ".svg", ".ico", ".tiff",
        // PDFs
        ".pdf",
        // Office documents
        ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx",
        ".odt", ".ods", ".odp",
        // Text
        ".txt", ".csv", ".rtf"
    };

    private static readonly Dictionary<string, List<byte[]>> FileSignatures = new()
    {
        { ".jpg", new List<byte[]> { new byte[] { 0xFF, 0xD8, 0xFF } } },
        { ".jpeg", new List<byte[]> { new byte[] { 0xFF, 0xD8, 0xFF } } },
        { ".png", new List<byte[]> { new byte[] { 0x89, 0x50, 0x4E, 0x47 } } },
        { ".gif", new List<byte[]> { new byte[] { 0x47, 0x49, 0x46 } } },
        { ".pdf", new List<byte[]> { new byte[] { 0x25, 0x50, 0x44, 0x46 } } },
        { ".bmp", new List<byte[]> { new byte[] { 0x42, 0x4D } } },
        { ".doc", new List<byte[]> { new byte[] { 0xD0, 0xCF, 0x11, 0xE0 } } },
        { ".xls", new List<byte[]> { new byte[] { 0xD0, 0xCF, 0x11, 0xE0 } } },
        { ".ppt", new List<byte[]> { new byte[] { 0xD0, 0xCF, 0x11, 0xE0 } } },
        { ".docx", new List<byte[]> { new byte[] { 0x50, 0x4B, 0x03, 0x04 } } },
        { ".xlsx", new List<byte[]> { new byte[] { 0x50, 0x4B, 0x03, 0x04 } } },
        { ".pptx", new List<byte[]> { new byte[] { 0x50, 0x4B, 0x03, 0x04 } } },
    };

    public FileUploadService(IWebHostEnvironment environment)
    {
        _environment = environment;
    }

    public bool IsAllowedFileType(string fileName)
    {
        var extension = Path.GetExtension(fileName);
        return !string.IsNullOrEmpty(extension) && AllowedExtensions.Contains(extension);
    }

    public bool IsAllowedFileSize(long fileSize)
    {
        return fileSize > 0 && fileSize <= MaxFileSize;
    }

    public async Task<FileUploadResult> UploadFileAsync(IFormFile file, string category)
    {
        if (file == null || file.Length == 0)
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file provided or file is empty."
            };
        }

        if (!IsAllowedFileSize(file.Length))
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File size exceeds the maximum allowed size of {MaxFileSize / (1024 * 1024)} MB."
            };
        }

        if (!IsAllowedFileType(file.FileName))
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File type '{Path.GetExtension(file.FileName)}' is not allowed. Allowed types: {string.Join(", ", AllowedExtensions)}"
            };
        }

        var extension = Path.GetExtension(file.FileName).ToLowerInvariant();

        // Validate file signature for known types
        if (FileSignatures.ContainsKey(extension))
        {
            using var reader = new BinaryReader(file.OpenReadStream());
            var headerBytes = reader.ReadBytes(FileSignatures[extension].Max(s => s.Length));
            var isValidSignature = FileSignatures[extension].Any(signature =>
                headerBytes.Length >= signature.Length &&
                headerBytes.Take(signature.Length).SequenceEqual(signature));

            if (!isValidSignature)
            {
                return new FileUploadResult
                {
                    Success = false,
                    ErrorMessage = "File content does not match its extension. The file may be corrupted or disguised."
                };
            }
        }

        var sanitizedCategory = SanitizePath(category ?? "general");
        var uploadsFolder = Path.Combine(_environment.WebRootPath, "uploads", sanitizedCategory);

        if (!Directory.Exists(uploadsFolder))
        {
            Directory.CreateDirectory(uploadsFolder);
        }

        var sanitizedOriginalName = SanitizeFileName(Path.GetFileNameWithoutExtension(file.FileName));
        var uniqueFileName = $"{sanitizedOriginalName}_{Guid.NewGuid():N}{extension}";
        var filePath = Path.Combine(uploadsFolder, uniqueFileName);

        using (var stream = new FileStream(filePath, FileMode.Create))
        {
            await file.CopyToAsync(stream);
        }

        var relativePath = $"/uploads/{sanitizedCategory}/{uniqueFileName}";

        return new FileUploadResult
        {
            Success = true,
            FilePath = relativePath,
            FileName = uniqueFileName,
            OriginalFileName = file.FileName,
            FileSize = file.Length,
            ContentType = file.ContentType
        };
    }

    private static string SanitizeFileName(string fileName)
    {
        var invalidChars = Path.GetInvalidFileNameChars();
        var sanitized = new string(fileName.Where(c => !invalidChars.Contains(c)).ToArray());
        sanitized = sanitized.Replace(" ", "_");
        if (sanitized.Length > 50)
            sanitized = sanitized.Substring(0, 50);
        return string.IsNullOrWhiteSpace(sanitized) ? "file" : sanitized;
    }

    private static string SanitizePath(string path)
    {
        var invalidChars = Path.GetInvalidPathChars().Concat(new[] { '/', '\\', '.', ' ' }).ToArray();
        var sanitized = new string(path.Where(c => !invalidChars.Contains(c)).ToArray());
        return string.IsNullOrWhiteSpace(sanitized) ? "general" : sanitized.ToLowerInvariant();
    }
}

public class FileUploadResult
{
    public bool Success { get; set; }
    public string? FilePath { get; set; }
    public string? FileName { get; set; }
    public string? OriginalFileName { get; set; }
    public long FileSize { get; set; }
    public string? ContentType { get; set; }
    public string? ErrorMessage { get; set; }
}

public class MultipleFileUploadResult
{
    public int TotalFiles { get; set; }
    public int SuccessfulUploads { get; set; }
    public int FailedUploads { get; set; }
    public List<FileUploadResult> Results { get; set; } = new();
}

[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly IFileUploadService _fileUploadService;

    public FileUploadController(IFileUploadService fileUploadService)
    {
        _fileUploadService = fileUploadService;
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(5 * 1024 * 1024)] // 5 MB for avatars
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        if (file == null)
            return BadRequest(new { error = "No file provided." });

        var allowedImageExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png", ".gif", ".webp", ".bmp"
        };

        var extension = Path.GetExtension(file.FileName);
        if (!allowedImageExtensions.Contains(extension))
        {
            return BadRequest(new { error = $"Avatars must be image files. Allowed types: {string.Join(", ", allowedImageExtensions)}" });
        }

        var result = await _fileUploadService.UploadFileAsync(file, "avatars");

        if (!result.Success)
            return BadRequest(new { error = result.ErrorMessage });

        return Ok(new
        {
            message = "Avatar uploaded successfully.",
            filePath = result.FilePath,
            fileName = result.FileName,
            originalFileName = result.OriginalFileName,
            fileSize = result.FileSize,
            contentType = result.ContentType
        });
    }

    [HttpPost("document")]
    [RequestSizeLimit(10 * 1024 * 1024)] // 10 MB for documents
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        if (file == null)
            return BadRequest(new { error = "No file provided." });

        var result = await _fileUploadService.UploadFileAsync(file, "documents");

        if (!result.Success)
            return BadRequest(new { error = result.ErrorMessage });

        return Ok(new
        {
            message = "Document uploaded successfully.",
            filePath = result.FilePath,
            fileName = result.FileName,
            originalFileName = result.OriginalFileName,
            fileSize = result.FileSize,
            contentType = result.ContentType
        });
    }

    [HttpPost("multiple")]
    [RequestSizeLimit(50 * 1024 * 1024)] // 50 MB total for multiple files
    public async Task<IActionResult> UploadMultipleFiles(List<IFormFile> files, [FromQuery] string? category = "general")
    {
        if (files == null || files.Count == 0)
            return BadRequest(new { error = "No files provided." });

        if (files.Count > 10)
            return BadRequest(new { error = "Maximum 10 files can be uploaded at once." });

        var multipleResult = new MultipleFileUploadResult
        {
            TotalFiles = files.Count
        };

        foreach (var file in files)
        {
            var result = await _fileUploadService.UploadFileAsync(file, category ?? "general");
            multipleResult.Results.Add(result);

            if (result.Success)
                multipleResult.SuccessfulUploads++;
            else
                multipleResult.FailedUploads++;
        }

        var statusCode = multipleResult.FailedUploads == 0 ? 200 :
                          multipleResult.SuccessfulUploads == 0 ? 400 : 207;

        return StatusCode(statusCode, new
        {
            message = $"{multipleResult.SuccessfulUploads} of {multipleResult.TotalFiles} files uploaded successfully.",
            totalFiles = multipleResult.TotalFiles,
            successfulUploads = multipleResult.SuccessfulUploads,
            failedUploads = multipleResult.FailedUploads,
            results = multipleResult.Results.Select(r => new
            {
                success = r.Success,
                filePath = r.FilePath,
                fileName = r.FileName,
                originalFileName = r.OriginalFileName,
                fileSize = r.FileSize,
                contentType = r.ContentType,
                errorMessage = r.ErrorMessage
            })
        });
    }

